```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

// Helper function to map table names to their corresponding types
std::map<std::string, std::type_index> table_to_type = {
    {"Student", std::type_index<Student>()},
    {"Course", std::type_index<Course>()},
    {"Score", std::type_index<Score>()},
    {"Major", std::type_index<Major>()}
};

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Map table name to type
  auto it = table_to_type.find(table_name);
  if (it == table_to_type.end()) {
    throw std::runtime_error("Unknown table: " + table_name);
  }
  std::type_index type_index = it->second;
  std::type_t<T> T = type_index.type();

  // Connect to database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Generate dynamic INSERT statement
  auto stmt = transpilation::to_insert_or_write<T, dynamic::Insert>(false);

  // Convert records to appropriate format
  std::vector<std::vector<std::optional<std::string>>> data;
  for (const auto& record : records) {
    std::vector<std::optional<std::string>> row;
    for (const auto& field : record) {
      if (field) {
        row.push_back(std::to_string(*field));
      } else {
        row.push_back(std::nullopt);
      }
    }
    data.push_back(std::move(row));
  }

  // Execute insert operation
  auto result = conn->insert(stmt, data.begin(), data.end());
  if (!result) {
    throw std::runtime_error("Failed to insert records");
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  // Map table name to type
  auto it = table_to_type.find(table_name);
  if (it == table_to_type.end()) {
    throw std::runtime_error("Unknown table: " + table_name);
  }
  std::type_index type_index = it->second;
  std::type_t<T> T = type_index.type();

  // Connect to database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Build DELETE statement
  auto delete_stmt = delete_from<T> | where("id"_c == record_id);

  // Convert to dynamic statement and execute
  dynamic::Statement stmt = delete_stmt;
  auto result = conn->execute(dynamic::sqlite::to_sql(stmt));
  if (!result) {
    throw std::runtime_error("Failed to delete record");
  }
}

void modify_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id,
                               const std::string& col_name,
                               const std::string& new_value) {
  // Map table name to type
  auto it = table_to_type.find(table_name);
  if (it == table_to_type.end()) {
    throw std::runtime_error("Unknown table: " + table_name);
  }
  std::type_index type_index = it->second;
  std::type_t<T> T = type_index.type();

  // Connect to database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Build UPDATE statement
  auto update_stmt = update<T>("id"_c.set(new_value)) | where("id"_c == record_id);

  // Convert to dynamic statement and execute
  dynamic::Statement stmt = update_stmt;
  auto result = conn->execute(dynamic::sqlite::to_sql(stmt));
  if (!result) {
    throw std::runtime_error("Failed to update record");
  }
}
```

## Key Implementation Details:

1. **Table Type Mapping**: Uses a `std::map` to associate table names with their corresponding C++ struct types for type-safe operations.

2. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish a connection to the SQLite database.

3. **Dynamic Statement Generation**: 
   - For `add_eas_records`: Uses `transpilation::to_insert_or_write()` to generate dynamic INSERT statements
   - For `delete_eas_records_by_id`: Uses `delete_from<T> | where()` to build DELETE statements
   - For `modify_eas_records_by_id`: Uses `update<T>() | where()` to build UPDATE statements

4. **Error Handling**: Includes proper error checking for database operations using the Result type pattern.

5. **Type Safety**: Leverages sqlgen's type system to ensure operations are performed on valid table structures.

The implementation follows sqlgen's functional programming style and properly handles the Result-based error handling pattern used throughout the library.

