    ASSERT_TRUE(has_column("Score", "CID"));
    ASSERT_TRUE(has_column("Score", "Score"));

    // Verify constraints
    // Check SNo is Primary Key in Student
    {
      const auto res = sqlgen::exec(conn, "SELECT 1 FROM pragma_table_info('Student') WHERE name='SNo' AND pk=1;");
      ASSERT_TRUE(res);
    }

